import { createCache } from 'ai/cache';

const promptCache = createCache();

export async function agentStream(messages: Message[]) {
  const cacheKey = JSON.stringify(messages[0].content); // System prompt

  const cachedPrompt = await promptCache.get(cacheKey);
  const finalPrompt = cachedPrompt || messages[0].content;

  if (!cachedPrompt) {
    await promptCache.set(cacheKey, finalPrompt);
  }

  return streamText({
    model: openai('gpt-4o'),
    messages: [{ role: 'system', content: finalPrompt }, ...messages.slice(1)]
  });
}

import { streamText } from 'ai';

export async function fastStream(messages: Message[]) {
  return streamText({
    model: openai('gpt-4o'),
    messages,
    maxTokens: 200, // Smaller chunks
    streamOptions: {
      includeUsage: false,
      includeExtra: false
    },
    experimental_streamingDelta: true // Faster deltas
  });
}

import { tool } from 'ai/rsc';

const dbTool = tool({ /* ... */ });
const cacheTool = tool({ /* ... */ });

export async function parallelTools({ dbId, cacheKey }: { dbId: string; cacheKey: string }) {
  const [dbResult, cacheResult] = await Promise.all([
    dbTool.execute({ id: dbId }),
    cacheTool.execute({ key: cacheKey })
  ]);

  return { db: dbResult, cache: cacheResult };
}

